function DefaultCurrency9120() {}
DefaultCurrency9120.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency9120.tabIndex = -1;
DefaultCurrency9120.maxLength = 1;
DefaultCurrency9120.isReadOnly = function(){return true;}
DefaultCurrency9120.isTemporary = function(){return true;}
DefaultCurrency9120.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency9120.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }

Context.validate:
				//Validation: only numeric characters allowed and two decimal places.
				//Error message: Currency amounts must be in the format of 0.00
				//Currency field. Max value. 999999.99
                  var value = Services.getValue(InterestToDateAmount.dataBinding);      
                  var maxVal = 999999.99;         
                  var err = null;
                  
                  if( '0.00 ' != value )
                  {   err = validateCurrencyValue(value, maxVal);
                      if( null == err)
                      { 
                        var returnVal = WPU.formatToTwoDP(value);
                        Services.setValue(InterestToDateAmount.dataBinding, returnVal);
                      } 
                  }
                  return err;

Context.transformToModel:

          if( null == value || "" == value )
          {  return "0.00 ";
          }
          else
          { return value;
          }
